// ==========================================
// プレイヤーの移動・カメラ制御
// ==========================================
public void updatePlayer() {
  // アンカーが刺さっていない時だけWASD移動可能
  if (!isAttached) {
    if (keyA) playerAngle += 0.03f; // 左旋回
    if (keyD) playerAngle -= 0.03f; // 右旋回
    if (keyW) playerDist -= WALK_SPEED; // 前進
    if (keyS) playerDist += WALK_SPEED; // 後退
    
    // 移動範囲の制限
    if (playerDist < 300) playerDist = 300;
    if (playerDist > MAX_DISTANCE) playerDist = MAX_DISTANCE;
    
    // 重力表現（ジャンプしていても徐々に地面の高さに戻る）
    playerY = lerp(playerY, 200, 0.1f);
  }
  
  // 視点操作（Qで見上げ、Eで見下げ）
  if (keyQ) cameraPitch += LOOK_SPEED; 
  if (keyE) cameraPitch -= LOOK_SPEED; 
  // 首が回りすぎないように角度制限
  cameraPitch = constrain(cameraPitch, -PI/2.1f, PI/6); 
  
  // 角度の正規化（一周回った時の処理）
  if (playerAngle > PI) playerAngle -= TWO_PI;
  if (playerAngle < -PI) playerAngle += TWO_PI;
}

// ==========================================
// 巨人のAI
// ==========================================
public void updateTitanAI() {
  // プレイヤーが張り付いている間は動けない
  if (isAttached) return;
  
  titanMoveTimer++;
  // 一定時間ごとにランダムに動く
  if (titanMoveTimer > 100) {
    titanRot += random(-0.05f, 0.05f); // 回転
    titanX += random(-3, 3); // 移動
    titanZ += random(-3, 3);
    // 移動範囲制限
    titanX = constrain(titanX, -1000, 1000);
    titanZ = constrain(titanZ, -1000, 1000);
    
    if (titanMoveTimer > 150) titanMoveTimer = 0;
  }
}

// ==========================================
// 3D空間の描画処理
// ==========================================
public void drawWorld() {
  pushMatrix();
  // 1. カメラ位置の設定
  translate(width/2, height/2); // 画面中央基準
  rotateX(cameraPitch); // 上下の視点回転
  translate(0, -playerY, -playerDist); // プレイヤー位置分ずらす
  rotateY(playerAngle); // 左右の視点回転
  
  // 2. ワールド座標系（巨人のいる場所）
  pushMatrix();
  translate(titanX, 0, titanZ); // 巨人の位置へ
  rotateY(titanRot); // 巨人の向き
  
  // 3. 巨人の描画（足元を地面に合わせる）
  translate(0, 500 - TITAN_HEIGHT/2, 0);
  drawTallTitan(TITAN_WIDTH, TITAN_HEIGHT);
  popMatrix();
  
  // 4. 背景オブジェクト（地面と森）
  drawGrid();
  drawForest();
  popMatrix();
}

// ==========================================
// 照準・ロックオン判定ロジック
// ==========================================
public void checkTargeting() {
  isTargetLocked = false;
  isNapeVisible = false;
  
  // 1. 背後にいるかどうかの判定（角度計算）
  float totalRot = (playerAngle + titanRot) % TWO_PI;
  if (totalRot < 0) totalRot += TWO_PI;
  float distFromBack = abs(totalRot - PI);
  // PI(180度)に近いほど背面（誤差0.6ラジアン以内ならOK）
  boolean isBehind = (distFromBack < 0.6f); 
  isNapeVisible = isBehind; 
  
  // 2. 画面上の位置判定（うなじが中央にあるか）
  float d = dist(napeScreenX, napeScreenY, width/2, height/2);
  boolean isInCircle = (d < 80); // 半径80px以内
  
  // 両方の条件を満たせばロックオン
  if (isBehind && isInCircle) {
    isTargetLocked = true;
  }
}

// アンカー発射処理
public void fireAnchor() {
  isAttached = true;
  // 発射エフェクト（黒い線）
  stroke(0); strokeWeight(3);
  line(width/2, height, width/2, height/2); 
  noStroke();
}

// 回転検知＆立体機動移動
public void detectRotationAndMove() {
  float cx = width / 2;
  float cy = height / 2;
  // マウスの現在角度を計算
  float currentAngle = atan2(mouseY - cy, mouseX - cx);
  
  // ワイヤー描画
  stroke(50); strokeWeight(3);
  line(width/2 - 150, height, width/2, height/2); 
  line(width/2 + 150, height, width/2, height/2); 
  noStroke();
  
  if (!isDragging) {
    lastMouseAngle = currentAngle;
    isDragging = true;
  } else {
    // 角度の変化量を計算
    float delta = currentAngle - lastMouseAngle;
    // 角度の切れ目（-PIとPI）を跨いだ時の補正
    if (delta > PI) delta -= TWO_PI;
    if (delta < -PI) delta += TWO_PI;
    
    // 回転量（絶対値）
    float rotationInput = abs(delta);
    
    // 一定以上回していれば移動
    if (rotationInput > 0.1f) {
      playerDist -= rotationInput * ANCHOR_SPEED; // 接近
      if (playerDist < 100) playerDist = 100;
      
      // 高さ制御：うなじの高さへ向かって上昇する
      float targetH = -TITAN_HEIGHT + 500; 
      playerY = lerp(playerY, targetH, 0.05f * rotationInput); 
      // カメラ角度も自動で少し正面に戻す
      cameraPitch = lerp(cameraPitch, 0, 0.02f);
    }
    lastMouseAngle = currentAngle;
  }
}

// ブレード処理
public void updateBladeTrail() {
  // マウス軌跡を保存
  mouseTrail.add(new PVector(mouseX, mouseY));
  if (mouseTrail.size() > TRAIL_LENGTH) mouseTrail.remove(0);
  
  // 軌跡が十分あれば判定
  if (mouseTrail.size() >= 3) {
    PVector s = mouseTrail.get(0); // 始点
    PVector e = mouseTrail.get(mouseTrail.size() - 1); // 終点
    float d = PVector.dist(s, e); // 移動距離
    
    // マウスが巨人のうなじ座標に近いかチェック
    float distToTitan = dist(mouseX, mouseY, napeScreenX, napeScreenY);    
    // 移動距離に応じてダメージ
    float damage = 0;
    if (distToTitan < 150) {  // (半径150px以内)
       damage = d * 2.5f;
    }
    if (damage > 15) { // 素早く動かさないとダメージが入らない
      enemyHP -= damage;
      // 斬撃エフェクト
      stroke(255, 255, 200); strokeWeight(10);
      line(s.x, s.y, e.x, e.y);
      noStroke();
      
      // 討伐判定
      if (enemyHP <= 0) {
        killCount++;
        flashColor = color(255); // 白フラッシュ
        resetEnemy(); // 次の敵へ
      }
    }
  }
}

// ==========================================
// 描画ヘルパー・UI表示
// ==========================================
public void drawReticle() {
  hint(DISABLE_DEPTH_TEST); // 最前面に描画
  noFill();

  strokeWeight(3);
  
  // 状態によってレティクル（照準線）の色を変える
  if (isAttached) {
    if (playerDist < ATTACK_RANGE) {
      stroke(255, 0, 0); // 攻撃可能距離（赤）
    } else {
      stroke(0, 255, 0); // 接近中（緑）
    }
  } else if (isTargetLocked) {
    stroke(255, 0, 0); // ロックオン（赤）
    fill(255, 0, 0); textAlign(CENTER); textSize(20);
    text("CLICK CENTER!", width/2, height/2 - 90);
    noFill();
  } else {
    stroke(200); // 圏外（白）
  }
  
  ellipse(width/2, height/2, 160, 160); // 中央円
  
  // 敵のHPバー
  if (enemyHP < MAX_HP) {
    noStroke();
    float barW = 400;
    fill(50, 0, 0); rect(width/2 - barW/2, 50, barW, 20); // 背景
    fill(255, 0, 0); rect(width/2 - barW/2, 50, map(enemyHP, 0, MAX_HP, 0, barW), 20); // 現在値
  }
  hint(ENABLE_DEPTH_TEST);
}

