// リザルト画面描画
public void drawResult() {
  hint(DISABLE_DEPTH_TEST);
  background(0); textAlign(CENTER, CENTER);
  
  fill(255); textSize(40);
  text("MISSION OVER", width/2, height/2 - 60);
  textSize(30);
  text("討伐数: " + killCount + " 体", width/2, height/2 + 20);
  
  // ランク判定
  String r = "D (家畜)"; int c = color(150);
  if (killCount >= RANK_S_THRESHOLD) { r = "S (人類最強)"; c = color(255, 215, 0); }
  else if (killCount >= RANK_A_THRESHOLD) { r = "A (精鋭)"; c = color(255, 100, 100); }
  else if (killCount >= RANK_B_THRESHOLD) { r = "B (調査兵)"; c = color(100, 100, 255); }
  else if (killCount >= RANK_C_THRESHOLD) { r = "C (訓練兵)"; c = color(100, 255, 100); }
  
  fill(c); textSize(50);
  text(r, width/2, height/2 + 100);
  
  fill(255); textSize(20);
  text("[R] RETURN TO TITLE", width/2, height - 50);
  
  // Rキーでタイトルへ戻る
  if (keyPressed && (key == 'r' || key == 'R')) currentState = STATE_TITLE;
  hint(ENABLE_DEPTH_TEST);
}

