// 巨人の描画
public void drawTallTitan(float w, float h) {
  float hw = w / 2;
  float hh = h / 2;
  
  // うなじ（赤い部分）を描画
  beginShape(QUADS); texture(napeTexture);
  vertex(hw, -hh, -hw, 0, 0);           
  vertex(-hw, -hh, -hw, 200, 0);        
  vertex(-hw, -hh + 300, -hw, 200, 200); 
  vertex(hw, -hh + 300, -hw, 0, 200);           
  endShape();
  
  // うなじの中心座標を画面座標(2D)に変換して保存
  // これにより「見た目通り」の当たり判定を実現
  napeScreenX = screenX(0, -hh + 150, -hw);
  napeScreenY = screenY(0, -hh + 150, -hw);
  
  // 背中（下部）
  fill(200, 150, 100); 
  beginShape(QUADS);
  vertex(hw, -hh + 300, -hw); vertex(-hw, -hh + 300, -hw); vertex(-hw, hh, -hw); vertex(hw, hh, -hw);
  endShape();
  
  // 顔（正面）
  beginShape(QUADS); texture(faceTexture);
  vertex(-hw, -hh, hw, 0, 0); vertex(hw, -hh, hw, 200, 0);
  vertex(hw, -hh + 400, hw, 200, 200); vertex(-hw, -hh + 400, hw, 0, 200); 
  endShape();
  
  // 体（正面）
  fill(200, 150, 100);
  beginShape(QUADS);
  vertex(-hw, -hh+400, hw); vertex(hw, -hh+400, hw); vertex(hw, hh, hw); vertex(-hw, hh, hw);
  endShape();
  
  // 側面
  fill(210, 160, 110); 
  beginShape(QUADS); vertex(hw, -hh, hw); vertex(hw, -hh, -hw); vertex(hw, hh, -hw); vertex(hw, hh, hw); endShape();
  beginShape(QUADS); vertex(-hw, -hh, -hw); vertex(-hw, -hh, hw); vertex(-hw, hh, hw); vertex(-hw, hh, -hw); endShape();
}

// 地面グリッドの描画
public void drawGrid() {
  // 地面（土）を描画
  noStroke();
  fill(100, 80, 50); // 茶色
  beginShape(QUADS);
  vertex(-4000, 500, -4000);
  vertex(4000, 500, -4000);
  vertex(4000, 500, 4000);
  vertex(-4000, 500, 4000);
  endShape();

  stroke(150, 130, 100); 
  strokeWeight(1);
  float groundY = 501; // 地面よりわずかに浮かせてちらつき防止
  for (int i = -4000; i < 4000; i+=400) { 
    line(i, groundY, -4000, i, groundY, 4000);
    line(-4000, groundY, i, 4000, groundY, i);
  }
  noStroke();
}

// 森の座標生成
public void createForest() {
  for(int i=0; i<50; i++) {
    float r = random(1000, 3500); 
    float theta = random(TWO_PI);
    treeX[i] = r * cos(theta);
    treeZ[i] = r * sin(theta);
    treeH[i] = random(1000, 2500);
  }
}

// 森の描画
public void drawForest() {
  fill(50, 40, 30); 
  for(int i=0; i<50; i++) {
    pushMatrix();
    translate(treeX[i], 500 - treeH[i]/2, treeZ[i]); 
    box(50, treeH[i], 50); // 幹
    translate(0, -treeH[i]/2, 0);
    fill(34, 139, 34); 
    box(200, 100, 200); // 葉
    fill(50, 40, 30); 
    popMatrix();
  }
}

// テクスチャの動的生成
public void createTextures() {
  // -------------------------------------------------
  // 顔テクスチャの生成
  // -------------------------------------------------
  faceTexture = createImage(200, 200, RGB);
  PGraphics pg = createGraphics(200, 200);
  pg.beginDraw();  
  // 肌色で塗りつぶし
  pg.background(220, 180, 140);
  pg.noStroke(); // 余計な線が入らないようにする
    // 目を描画（赤）
  pg.fill(200, 0, 0);
  pg.arc(30, 40, 40, 30, 0.5f, PI+0.5f);   // 右目
  pg.arc(70, 40, 40, 30, -0.5f, PI-0.5f);  // 左目  
  // 口を描画（白）
  pg.fill(200);
  pg.rect(25, 65, 50, 20);  // 口  
  pg.endDraw(); 
  faceTexture = pg.get();
  
  // -------------------------------------------------
  // うなじテクスチャ
  // -------------------------------------------------
  napeTexture = createImage(200, 200, RGB);
  pg = createGraphics(200, 200);
  pg.beginDraw(); 
  pg.background(220, 180, 140); 
  pg.noStroke();
  for(int i=0; i<50; i++) {
    pg.fill(150+random(100), 0, 0);
    pg.ellipse(random(200), random(200), 20 + random(20), 10 + random(10));
  }
  pg.endDraw(); 
  napeTexture = pg.get();
}

// キー入力管理
public void keyPressed() {
  if (key == 'w' || key == 'W') keyW = true;
  if (key == 'a' || key == 'A') keyA = true;
  if (key == 's' || key == 'S') keyS = true;
  if (key == 'd' || key == 'D') keyD = true;
  if (key == 'e' || key == 'E') keyE = true;
  if (key == 'q' || key == 'Q') keyQ = true;
}

public void keyReleased() {
  if (key == 'w' || key == 'W') keyW = false;
  if (key == 'a' || key == 'A') keyA = false;
  if (key == 's' || key == 'S') keyS = false;
  if (key == 'd' || key == 'D') keyD = false;
  if (key == 'e' || key == 'E') keyE = false;
  if (key == 'q' || key == 'Q') keyQ = false;
}


